document.querySelectorAll('.toggle-password').forEach(function (btn) {
      btn.addEventListener('click', function () {
        var input = document.getElementById(btn.getAttribute('data-target'));
        var isHidden = input.type === 'password';
        input.type = isHidden ? 'text' : 'password';
        btn.classList.toggle('is-visible', isHidden);
        btn.setAttribute('aria-label', isHidden ? 'Hide password' : 'Show password');
      });
    });

    var newPasswordForm = document.getElementById('newPasswordForm');
    var newPasswordInput = document.getElementById('newPassword');
    var confirmPasswordInput = document.getElementById('confirmPassword');
    var strengthChecklist = document.getElementById('strengthChecklist');
    var strengthChecklistItems = document.querySelectorAll('#strengthChecklist li');
    var matchMessage = document.getElementById('matchMessage');
    var successOverlay = document.getElementById('successOverlay');
    var backToLoginBtn = document.getElementById('backToLoginBtn');

    function getPasswordScore(password) {
      var score = 0;
      if (password.length >= 8) score += 1;
      if (password.length >= 12) score += 1;
      if (/[a-z]/.test(password)) score += 1;
      if (/[A-Z]/.test(password)) score += 1;
      if (/[0-9]/.test(password)) score += 1;
      if (/[^A-Za-z0-9]/.test(password)) score += 1;
      return score;
    }

    function getPasswordChecks(password) {
      return {
        length: password.length >= 8,
        case: /[a-z]/.test(password) && /[A-Z]/.test(password),
        number: /[0-9]/.test(password),
        special: /[^A-Za-z0-9]/.test(password)
      };
    }

    function isPasswordStrong(password) {
      var checks = getPasswordChecks(password);
      return checks.length && checks.case && checks.number && checks.special;
    }

    function updateStrengthMeter() {
      var password = newPasswordInput.value;
      var score = getPasswordScore(password);
      var level = 'weak';
      var checks = getPasswordChecks(password);

      if (!password) {
        strengthChecklist.className = 'strength-checklist';
        strengthChecklistItems.forEach(function (item) {
          item.classList.remove('is-met');
        });
        return;
      }

      if (score <= 2) {
        level = 'weak';
      } else if (score <= 4) {
        level = 'medium';
      } else {
        level = 'strong';
      }

      strengthChecklist.className = 'strength-checklist is-' + level;

      strengthChecklistItems.forEach(function (item) {
        var checkName = item.getAttribute('data-check');
        item.classList.toggle('is-met', !!checks[checkName]);
      });
    }

    function updateMatchMessage() {
      var password = newPasswordInput.value;
      var confirm = confirmPasswordInput.value;

      matchMessage.className = 'match-message';

      if (!confirm) {
        return true;
      }

      if (password === confirm && password.length > 0) {
        matchMessage.textContent = 'Password matched!';
        matchMessage.classList.add('is-match');
        return true;
      }

      matchMessage.textContent = "Password doesn't match.";
      matchMessage.classList.add('is-mismatch');
      return false;
    }

    newPasswordInput.addEventListener('input', function () {
      updateStrengthMeter();
      updateMatchMessage();
    });
    confirmPasswordInput.addEventListener('input', updateMatchMessage);

    newPasswordForm.addEventListener('submit', function (event) {
      event.preventDefault();

      if (!isPasswordStrong(newPasswordInput.value)) {
        newPasswordInput.focus();
        return;
      }

      if (!updateMatchMessage()) {
        confirmPasswordInput.focus();
        return;
      }

      successOverlay.classList.add('is-open');
    });

    backToLoginBtn.addEventListener('click', function () {
      window.location.href = '/login';
    });
